        if edge[0] == edge[1]-1:
            EP[edge]["cardinal_angle"] = 90
        elif edge[0] == edge[1]+1:
            EP[edge]["cardinal_angle"] = 270
        elif edge[0] == edge[1]-12:
            EP[edge]["cardinal_angle"] = 0
        elif edge[0] == edge[1]+12:
            EP[edge]["cardinal_angle"] = 180
        else:
